USE driving_exam;

CREATE TEMPORARY TABLE IF NOT EXISTS temp_question_seed_20260509 (
  category_id INT NOT NULL,
  type VARCHAR(20) NOT NULL,
  content TEXT NOT NULL,
  options TEXT,
  answer VARCHAR(50) NOT NULL,
  analysis TEXT,
  difficulty TINYINT DEFAULT 3,
  chapter VARCHAR(50),
  knowledge_point VARCHAR(100) NOT NULL
) DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

TRUNCATE TABLE temp_question_seed_20260509;


SELECT t.category_id, t.type, t.content, NULL, t.options, t.answer, t.analysis, t.difficulty, t.chapter, t.knowledge_point, NOW(), NOW()
FROM temp_question_seed_20260509 t
WHERE NOT EXISTS (
  SELECT 1 FROM question q
  WHERE q.knowledge_point COLLATE utf8mb4_unicode_ci = t.knowledge_point COLLATE utf8mb4_unicode_ci
);

DROP TEMPORARY TABLE IF EXISTS temp_question_seed_20260509;
